// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Parity and eligibility tests for the symmetric leapfrog merge join: results must equal the generic engine's bag
 * semantics in every mode (buffered runs, seeks, overflow rescans), and ineligible joins must decline so the hash join
 * or nested-loop strategies keep serving them.
 */
class LmdbNativeMergeJoinTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String MANY_TO_MANY_QUERY = "PREFIX ex: <" + EX + ">\n"
			+ "SELECT ?left ?key ?right WHERE { ?left ex:key ?key . ?right ex:key ?key }";
	private static final String SPARSE_QUERY = "PREFIX ex: <" + EX + ">\n"
			+ "SELECT ?s ?v ?o WHERE { ?s ex:q ?v . ?s ex:p ?o }";

	@TempDir
	File dataDir;

	SailRepository repository;

	@BeforeEach
	void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI key = vf.createIRI(EX, "key");
			for (int i = 0; i < 200; i++) {
				connection.add(vf.createIRI(EX, "row" + i), key, vf.createIRI(EX, "key" + (i % 20)));
			}
		}
		System.setProperty(NativeBatch.ENABLED_PROPERTY, "true");
		System.setProperty(NativeBatch.ROWS_PROPERTY, "31");
		System.setProperty(LmdbNativeMergeJoin.MIN_ROWS_PROPERTY, "0");
		System.setProperty(LmdbNativeHashJoin.MIN_ROWS_PROPERTY, "0");
	}

	@AfterEach
	void tearDown() {
		System.clearProperty(NATIVE_FLAG);
		System.clearProperty(NativeBatch.ENABLED_PROPERTY);
		System.clearProperty(NativeBatch.ROWS_PROPERTY);
		System.clearProperty(LmdbNativeMergeJoin.ENABLED_PROPERTY);
		System.clearProperty(LmdbNativeMergeJoin.MIN_ROWS_PROPERTY);
		System.clearProperty(LmdbNativeMergeJoin.MAX_RUN_ROWS_PROPERTY);
		System.clearProperty(LmdbNativeHashJoin.ENABLED_PROPERTY);
		System.clearProperty(LmdbNativeHashJoin.MIN_ROWS_PROPERTY);
		repository.shutDown();
	}

	private void addSparseData() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI dense = vf.createIRI(EX, "p");
			IRI sparse = vf.createIRI(EX, "q");
			for (int i = 0; i < 3000; i++) {
				IRI subject = vf.createIRI(EX, "subject" + i);
				connection.add(subject, dense, vf.createIRI(EX, "object" + i));
				if (i % 30 == 0) {
					connection.add(subject, sparse, vf.createIRI(EX, "value" + i));
				}
			}
		}
	}

	@Test
	void manyToManyRunsMatchGenericBagSemanticsWithoutSeeking() {
		List<String> generic = genericRows(MANY_TO_MANY_QUERY);
		resetCounters();

		assertThat(rows(MANY_TO_MANY_QUERY)).isEqualTo(generic).hasSize(2000);
		assertThat(LmdbNativeMergeJoin.JOINS.get()).isOne();
		assertThat(LmdbNativeMergeJoin.BATCHES.get()).isPositive();
		// both cursors walk the same adjacent key runs: the lag never reaches the seek threshold
		assertThat(LmdbNativeMergeJoin.SEEKS.get()).isZero();
		assertThat(LmdbNativeMergeJoin.RUN_RESCANS.get()).isZero();
		// merge pre-empts the hash join when both are eligible
		assertThat(LmdbNativeHashJoin.BUILDS.get()).isZero();
	}

	@Test
	void sparseOverlapLeapfrogsWithSeeks() {
		addSparseData();
		List<String> generic = genericRows(SPARSE_QUERY);
		resetCounters();

		assertThat(rows(SPARSE_QUERY)).isEqualTo(generic).hasSize(100);
		assertThat(LmdbNativeMergeJoin.JOINS.get()).isOne();
		// the dense side lags ~30 rows between matches, far past the 8-miss threshold
		assertThat(LmdbNativeMergeJoin.SEEKS.get()).isPositive();
	}

	@Test
	void runOverflowRescansRepeatedLeftRows() {
		List<String> generic = genericRows(MANY_TO_MANY_QUERY);
		resetCounters();
		// runs are 10 rows per key: a cap of 4 forces the stream-tail + probe-rescan path
		System.setProperty(LmdbNativeMergeJoin.MAX_RUN_ROWS_PROPERTY, "4");

		assertThat(rows(MANY_TO_MANY_QUERY)).isEqualTo(generic).hasSize(2000);
		assertThat(LmdbNativeMergeJoin.JOINS.get()).isOne();
		assertThat(LmdbNativeMergeJoin.RUN_RESCANS.get()).isPositive();
	}

	@Test
	void disabledMergeJoinFallsBackToHashJoin() {
		List<String> generic = genericRows(MANY_TO_MANY_QUERY);
		resetCounters();
		System.setProperty(LmdbNativeMergeJoin.ENABLED_PROPERTY, "false");

		assertThat(rows(MANY_TO_MANY_QUERY)).isEqualTo(generic).hasSize(2000);
		assertThat(LmdbNativeMergeJoin.JOINS.get()).isZero();
		assertThat(LmdbNativeHashJoin.BUILDS.get()).isOne();
	}

	@Test
	void minRowsGateDeclines() {
		List<String> generic = genericRows(MANY_TO_MANY_QUERY);
		resetCounters();
		System.setProperty(LmdbNativeMergeJoin.MIN_ROWS_PROPERTY, "1000000");

		assertThat(rows(MANY_TO_MANY_QUERY)).isEqualTo(generic).hasSize(2000);
		assertThat(LmdbNativeMergeJoin.JOINS.get()).isZero();
	}

	@Test
	void twoSharedVariablesDeclineToHashJoin() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI key2 = vf.createIRI(EX, "key2");
			for (int i = 0; i < 200; i++) {
				connection.add(vf.createIRI(EX, "row" + i), key2, vf.createIRI(EX, "key" + (i % 20)));
			}
		}
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?row ?key WHERE { ?row ex:key ?key . ?row ex:key2 ?key }";
		List<String> generic = genericRows(query);
		resetCounters();

		assertThat(rows(query)).isEqualTo(generic).hasSize(200);
		assertThat(LmdbNativeMergeJoin.JOINS.get()).isZero();
	}

	@Test
	void correlatedFragmentEntryDeclines() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI p3 = vf.createIRI(EX, "p3");
			for (int i = 0; i < 20; i++) {
				IRI subject = vf.createIRI(EX, "s" + i);
				IRI bridge = vf.createIRI(EX, "b" + i);
				connection.add(subject, p1, vf.createIRI(EX, "a" + i));
				connection.add(subject, p2, bridge);
				connection.add(bridge, p3, vf.createIRI(EX, "c" + i));
			}
		}
		String correlated = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s (COUNT(DISTINCT ?b) AS ?cnt) WHERE { ?s ex:p1 ?a .\n"
				+ "  OPTIONAL { ?s ex:p2 ?b . ?b ex:p3 ?c . BIND(?c AS ?c2) }\n"
				+ "  FILTER(?c2 != ?s)\n"
				+ "  FILTER EXISTS { ?b ex:p3 ?c3 }\n"
				+ "} GROUP BY ?s";
		List<String> generic = genericRows(correlated);
		resetCounters();

		assertThat(rows(correlated)).isEqualTo(generic).hasSize(20);
		assertThat(LmdbNativeMergeJoin.JOINS.get()).isZero();
	}

	private List<String> genericRows(String query) {
		System.setProperty(NATIVE_FLAG, "false");
		try {
			return rows(query);
		} finally {
			System.clearProperty(NATIVE_FLAG);
		}
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			return QueryResults.asList(connection.prepareTupleQuery(query).evaluate())
					.stream()
					.map(LmdbNativeMergeJoinTest::canonical)
					.sorted()
					.collect(Collectors.toList());
		}
	}

	private static String canonical(BindingSet bindings) {
		return bindings.getBindingNames()
				.stream()
				.sorted()
				.map(name -> name + "=" + bindings.getValue(name))
				.collect(Collectors.joining(";", "[", "]"));
	}

	private static void resetCounters() {
		LmdbNativeMergeJoin.JOINS.set(0);
		LmdbNativeMergeJoin.BATCHES.set(0);
		LmdbNativeMergeJoin.SEEKS.set(0);
		LmdbNativeMergeJoin.RUN_RESCANS.set(0);
		LmdbNativeHashJoin.BUILDS.set(0);
		LmdbNativeHashJoin.PROBE_BATCHES.set(0);
		LmdbNativeHashJoin.CAP_FALLBACKS.set(0);
	}
}
